# .bazelrc: configure remote cache
build --remote_cache=grpcs://remote.buildbuddy.io
build --remote_header=x-buildbuddy-api-key=$BUILDBUDDY_API_KEY
build --remote_upload_local_results=true

# Turborepo remote cache (alternative for JS monorepos)
# turbo.json
{
  "remoteCache": {
    "signature": true
  }
}
# TURBO_TOKEN and TURBO_TEAM set in environment

# LaunchDarkly experiment flag configuration
{
  "key": "checkout-flow-v2",
  "kind": "experiment",
  "variations": [
    {"value": "control"},
    {"value": "variant-b"}
  ],
  "rules": [
    {
      "rollout": {
        "bucketBy": "user.key",
        "variations": [
          {"variation": 0, "weight": 50000},
          {"variation": 1, "weight": 50000}
        ]
      }
    }
  ],
  "trackEvents": true,
  "metricKeys": ["checkout-conversion", "revenue-per-session"]
}
